import type { IconDefinition } from "@fortawesome/fontawesome-svg-core";
import {
  faDocker,
  faGitAlt,
  faNodeJs,
  faPython,
  faReact,
} from "@fortawesome/free-brands-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { LogoLoop } from "@ui/LogoLoop";

type SvgPath = {
  d: string;
  fill?: string;
  fillRule?: "evenodd" | "nonzero";
};

type TechEntry =
  | { kind: "fa"; icon: IconDefinition; label: string }
  | {
      kind: "svg";
      paths: SvgPath[];
      viewBox?: string;
      /** fill="none" + stroke="currentColor" — outline icon */
      strokeOnly?: boolean;
      /** stroke-width in viewBox units; activates stroke even on fill icons when set */
      strokeWidth?: number;
      label: string;
    };

type TechSize = "sm" | "md" | "lg" | "xl" | "2xl";

const SIZE_CONFIG: Record<
  TechSize,
  { icon: number; fontSize: number; logoHeight: number; gap: number }
> = {
  sm:   { icon: 14, fontSize: 10, logoHeight: 14, gap: 20 },
  md:   { icon: 18, fontSize: 12, logoHeight: 18, gap: 28 },
  lg:   { icon: 22, fontSize: 13, logoHeight: 22, gap: 32 },
  xl:   { icon: 28, fontSize: 14, logoHeight: 28, gap: 40 },
  "2xl": { icon: 36, fontSize: 16, logoHeight: 36, gap: 48 },
};

function TechIcon({ size = "md", ...entry }: TechEntry & { size?: TechSize }) {
  const { icon: iconSize, fontSize } = SIZE_CONFIG[size];
  const hasStroke =
    entry.kind === "svg" && (entry.strokeOnly || entry.strokeWidth != null);
  return (
    <span
      className="inline-flex items-center gap-2"
      title={entry.label}
      aria-label={entry.label}
    >
      {entry.kind === "fa" ? (
        <FontAwesomeIcon
          icon={entry.icon}
          aria-hidden="true"
          style={{ width: iconSize, height: iconSize, flexShrink: 0 }}
        />
      ) : (
        <svg
          width={iconSize}
          height={iconSize}
          viewBox={entry.viewBox ?? "0 0 24 24"}
          fill={entry.strokeOnly ? "none" : "currentColor"}
          stroke={hasStroke ? "currentColor" : undefined}
          strokeWidth={
            entry.strokeWidth ?? (entry.strokeOnly ? 1.5 : undefined)
          }
          aria-hidden="true"
          style={{ flexShrink: 0 }}
        >
          {entry.paths.map((p, i) => (
            <path key={i} d={p.d} fill={p.fill} fillRule={p.fillRule} />
          ))}
        </svg>
      )}
      <span
        className="font-medium"
        style={{
          color: "var(--color-muted)",
          letterSpacing: "0.02em",
          fontSize,
        }}
      >
        {entry.label}
      </span>
    </span>
  );
}

