export function TechStack({ size = "lg" }: { size?: TechSize }) {
  const cfg = SIZE_CONFIG[size];
  const logos = TECH.map((entry) => ({
    node: <TechIcon {...entry} size={size} />,
    ariaLabel: entry.label,
  }));
  return (
    <div
      className="py-8"
      style={{ borderTop: "1px solid var(--color-border)" }}
    >
      <LogoLoop
        logos={logos}
        speed={55}
        gap={cfg.gap}
        logoHeight={cfg.logoHeight}
        fadeOut
        fadeOutColor="var(--color-bg)"
        pauseOnHover
        scaleOnHover
        ariaLabel="Stack de tecnologias"
        style={{ color: "var(--color-muted)" }}
      />
    </div>
  );
}
